const { detectIntent, buildQdrantFilter } = require('./src/intent-detector');

// Test 1: Query with language + tags → language in must, tags in should
const testCases = [
  { query: 'javascript code for React component', desc: 'lang+tags → lang must, tags should' },
  { query: 'Python utility function', desc: 'single language → lang must only' },
  { query: 'async pattern help', desc: 'no filters → null filter' },
  { query: 'Go Kubernetes deployment config', desc: 'lang+type → both in must' },
];

let allPass = true;
for (const tc of testCases) {
  const intent = detectIntent(tc.query);
  const filter = buildQdrantFilter(intent);
  console.log('---');
  console.log('Test:', tc.desc);
  console.log('Query:', tc.query);
  console.log('Intent filters:', JSON.stringify(intent.filters));
  console.log('Filter:', JSON.stringify(filter));

  // Verify: language/type always in must when present
  if (intent.filters.language) {
    const langInMust = filter?.must?.some(m => m.key === 'language');
    if (!langInMust) { allPass = false; console.log('❌ FAIL: language not in must'); }
    else console.log('✅ PASS: language in must[]');
  }
  if (intent.filters.tags && intent.filters.tags.length > 0) {
    const tagsInShould = filter?.should?.some(s => s.key === 'tags');
    if (!tagsInShould) { allPass = false; console.log('❌ FAIL: tags not in should'); }
    else console.log('✅ PASS: tags in should[]');
  }
}

console.log('\n' + (allPass ? '✅ All tests passed' : '❌ Some tests failed'));
"

